class Solution:
    def minLength(self, s: str) -> int:
        # Only "AB" and "CD" removals are allowed.
        # Greedy with stack works:
        # - When we see "...A" followed by "B", they cancel.
        # - When we see "...C" followed by "D", they cancel.
        stack = []
        for ch in s:
            stack.append(ch)
            if len(stack) >= 2:
                a, b = stack[-2], stack[-1]
                if (a == 'A' and b == 'B') or (a == 'C' and b == 'D'):
                    stack.pop()
                    stack.pop()
        return len(stack)
```

